import React, { useState, useMemo, useEffect } from 'react';
import { Ticket, Station, Service, TicketStatus } from '../types';

interface StaffViewProps {
  station: Station;
  tickets: Ticket[];
  services: Service[];
  onStatusUpdate: (ticketId: string, status: TicketStatus, stationId: string) => void;
}

const StaffView: React.FC<StaffViewProps> = ({ station, tickets, services, onStatusUpdate }) => {
  const [elapsedTime, setElapsedTime] = useState(0);

  // Tickets relevantes: Se filtran aquellos cuyos servicios aún existan y estén asignados al módulo
  const relevantTickets = useMemo(() => 
    tickets.filter(t => 
      station.serviceIds.includes(t.serviceId) && 
      services.some(s => s.id === t.serviceId)
    ),
  [tickets, station.serviceIds, services]);

  const waitingTickets = relevantTickets.filter(t => t.status === TicketStatus.WAITING);

  // Ticket activo en este módulo
  const activeTicket = tickets.find(t => t.stationId === station.id && 
    (t.status === TicketStatus.CALLING || t.status === TicketStatus.ATTENDING));

  useEffect(() => {
    let interval: any;
    if (activeTicket?.status === TicketStatus.ATTENDING) {
      interval = setInterval(() => {
        setElapsedTime(Math.floor((Date.now() - (activeTicket.startedAt || Date.now())) / 1000));
      }, 1000);
    } else {
      setElapsedTime(0);
    }
    return () => clearInterval(interval);
  }, [activeTicket]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const getWaitTime = (createdAt: number) => {
    const diff = Math.floor((Date.now() - createdAt) / 60000);
    return diff > 0 ? `${diff}m` : 'Reciente';
  };

  const currentService = activeTicket ? services.find(s => s.id === activeTicket.serviceId) : null;

  return (
    <div className="w-[450px] shrink-0 snap-center flex flex-col gap-4 animate-fade-in h-[calc(100vh-200px)]">
      {/* Header del Módulo */}
      <div className="bg-white p-5 rounded-3xl shadow-sm border border-slate-100 flex justify-between items-center shrink-0">
        <div>
          <div className="flex items-center gap-2 mb-1">
            <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Módulo Operativo Activo</p>
          </div>
          <h2 className="text-xl font-black text-slate-900 tracking-tight">{station.name}</h2>
          <p className="text-xs text-slate-500 font-medium">Op: <span className="text-slate-900 font-bold">{station.operatorName}</span></p>
        </div>
        <div className="flex -space-x-1.5">
          {station.serviceIds.map(id => {
            const s = services.find(sv => sv.id === id);
            if (!s) return null;
            return (
              <div key={id} title={s.name} className="w-8 h-8 rounded-full border-2 border-white flex items-center justify-center text-[8px] font-black text-white shadow-sm" style={{ backgroundColor: s.color }}>
                {s.prefix}
              </div>
            );
          })}
        </div>
      </div>

      {/* Cuerpo del Módulo: Apilado verticalmente para permitir el scroll horizontal del conjunto */}
      <div className="flex flex-col gap-4 flex-grow overflow-hidden">

        {/* Management Area (Ahora arriba para mayor visibilidad en cards estrechas) */}
        <div className="bg-white rounded-[2.5rem] shadow-xl shadow-slate-200/50 border border-slate-100 h-[380px] shrink-0 flex flex-col justify-center text-center p-8 relative overflow-hidden">
          {activeTicket ? (
            <div className="space-y-6 animate-fade-in">
              <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-[0.2em] text-white mx-auto shadow-sm" style={{ backgroundColor: currentService?.color || '#333' }}>
                 <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/></svg>
                 {currentService?.name || 'Servicio Desconocido'}
              </div>

              <div>
                <h1 className="text-[70px] font-black text-slate-900 leading-none tracking-tighter">{activeTicket.code}</h1>
                <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest mt-1">Ticket en Atención</p>
              </div>

              {activeTicket.status === TicketStatus.CALLING ? (
                <div className="space-y-4 pt-4">
                  <div className="flex flex-col items-center gap-1.5">
                    <div className="flex gap-1">
                      <div className="w-1.5 h-1.5 bg-blue-600 rounded-full animate-bounce" style={{ animationDelay: '0s' }}></div>
                      <div className="w-1.5 h-1.5 bg-blue-600 rounded-full animate-bounce" style={{ animationDelay: '0.1s' }}></div>
                      <div className="w-1.5 h-1.5 bg-blue-600 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                    </div>
                    <p className="text-blue-600 font-black uppercase tracking-widest text-[11px]">Notificando Paciente</p>
                  </div>
                  <div className="flex justify-center gap-3">
                    <button 
                      onClick={() => onStatusUpdate(activeTicket.id, TicketStatus.ATTENDING, station.id)}
                      className="flex-1 py-4 bg-emerald-600 text-white font-black rounded-xl shadow-lg shadow-emerald-100 hover:bg-emerald-700 active:scale-95 transition-all text-base"
                    >
                      Iniciar
                    </button>
                    <button 
                      onClick={() => onStatusUpdate(activeTicket.id, TicketStatus.CANCELLED, station.id)}
                      className="px-6 py-4 bg-red-50 text-red-600 font-black rounded-xl hover:bg-red-100 active:scale-95 transition-all text-[10px] uppercase tracking-widest"
                    >
                      Ausente
                    </button>
                  </div>
                </div>
              ) : (
                <div className="space-y-6 pt-4">
                  <div className="bg-slate-50 inline-block px-8 py-3 rounded-2xl border border-slate-100">
                    <div className="text-4xl font-mono font-black text-slate-800 tracking-tight tabular-nums">
                      {formatTime(elapsedTime)}
                    </div>
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">Tiempo Actual</p>
                  </div>
                  <button 
                    onClick={() => onStatusUpdate(activeTicket.id, TicketStatus.COMPLETED, station.id)}
                    className="w-full py-4 bg-slate-900 text-white font-black rounded-xl shadow-xl shadow-slate-300 hover:bg-slate-800 active:scale-95 transition-all text-lg"
                  >
                    Finalizar Atención
                  </button>
                </div>
              )}
            </div>
          ) : (
            <div className="space-y-4 py-8 opacity-60">
              <div className="w-20 h-20 bg-slate-50 rounded-[2rem] border border-slate-100 flex items-center justify-center mx-auto text-slate-200">
                <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v4"/><path d="m16.2 7.8 2.9-2.9"/><path d="M18 12h4"/><path d="m16.2 16.2 2.9 2.9"/><path d="M12 18v4"/><path d="m4.9 19.1 2.9-2.9"/><path d="M2 12h4"/><path d="m4.9 4.9 2.9 2.9"/></svg>
              </div>
              <div className="max-w-xs mx-auto">
                <h3 className="text-xl font-black text-slate-900 tracking-tight mb-1">Módulo Disponible</h3>
                <p className="text-xs text-slate-500 font-medium leading-tight italic">Esperando llamado...</p>
              </div>
            </div>
          )}
        </div>

        {/* Queue Column (Ahora abajo y scrollable) */}
        <div className="flex-grow bg-white rounded-[2rem] shadow-sm border border-slate-100 flex flex-col overflow-hidden min-h-0">
          <div className="p-4 bg-slate-50 border-b border-slate-100 flex justify-between items-center shrink-0">
            <h3 className="font-black text-slate-800 uppercase tracking-wider text-[10px]">Lista de Espera</h3>
            <span className="bg-slate-900 text-white text-[9px] font-black px-1.5 py-0.5 rounded-md">{waitingTickets.length}</span>
          </div>
          <div className="flex-grow overflow-y-auto divide-y divide-slate-50 scrollbar-hide">
            {waitingTickets.length === 0 ? (
              <div className="p-8 text-center text-slate-400">
                <p className="font-bold italic text-xs">Sin pendientes</p>
              </div>
            ) : (
              waitingTickets.map((t, idx) => (
                <div key={t.id} className="p-4 flex justify-between items-center hover:bg-slate-50 transition-colors animate-fade-in" style={{ animationDelay: `${idx * 0.05}s` }}>
                  <div>
                    <span className="text-[9px] font-black text-slate-400 uppercase block">Paciente • {getWaitTime(t.createdAt)}</span>
                    <span className="text-lg font-black text-slate-900 tracking-tighter">{t.code}</span>
                  </div>
                  <button 
                    onClick={() => onStatusUpdate(t.id, TicketStatus.CALLING, station.id)}
                    disabled={!!activeTicket}
                    className="px-4 py-2 bg-blue-600 text-white text-[10px] font-black uppercase tracking-widest rounded-lg hover:bg-blue-700 disabled:opacity-20 transition-all shadow-md shadow-blue-100"
                  >
                    Llamar
                  </button>
                </div>
              ))
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default StaffView;

import React, { useState } from 'react';
import { HashRouter as Router, Routes, Route, Link, useLocation, Navigate } from 'react-router-dom';
import { useQmsStore } from './store/useQmsStore';
import { ICONS } from './constants';
import { UserRole, User, Service, Station, QmsState } from './types';
import TotemView from './components/TotemView';
import StaffView from './components/StaffView';
import DashboardView from './components/DashboardView';
import TechnicalInfoView from './components/TechnicalInfoView';
import PublicDisplayView from './components/PublicDisplayView';
import LoginView from './components/LoginView';
import UserManagementView from './components/UserManagementView';
import ServiceManagementView from './components/ServiceManagementView';
import StationManagementView from './components/StationManagementView';

const Nav: React.FC<{ role: UserRole, logout: () => void, currentUser: User }> = ({ role, logout, currentUser }) => {
  const location = useLocation();
  const isActive = (path: string) => location.pathname === path;

  const canSee = (targetRole: UserRole[]) => targetRole.includes(role);

  return (
    <nav className="fixed bottom-10 left-1/2 -translate-x-1/2 dock-nav text-white px-8 py-5 rounded-[3rem] shadow-2xl z-50 flex items-center gap-10">
      <div className="flex items-center gap-4 pr-8 border-r border-white/10 hidden md:flex">
         <div className="w-11 h-11 rounded-2xl bg-indigo-500/20 border border-indigo-500/30 flex items-center justify-center font-black text-indigo-400 text-lg">
           {currentUser.name[0]}
         </div>
         <div>
            <p className="text-[10px] font-black text-white/40 uppercase tracking-[0.2em] leading-none mb-1">Session</p>
            <p className="text-[13px] font-bold tracking-tight">{currentUser.username}</p>
         </div>
      </div>

      <div className="flex items-center gap-8">
        {canSee([UserRole.TOTEM, UserRole.ADMIN, UserRole.SUPERADMIN]) && (
          <Link title="Totem" to="/" className={`flex flex-col items-center gap-1.5 transition-all group ${isActive('/') ? 'text-indigo-400 scale-110' : 'text-slate-500 hover:text-white'}`}>
            <ICONS.Terminal />
            <span className={`text-[9px] font-black uppercase tracking-widest transition-opacity ${isActive('/') ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>Totem</span>
          </Link>
        )}
        {canSee([UserRole.STAFF, UserRole.ADMIN, UserRole.SUPERADMIN]) && (
          <Link title="Módulo" to="/staff" className={`flex flex-col items-center gap-1.5 transition-all group ${isActive('/staff') ? 'text-indigo-400 scale-110' : 'text-slate-500 hover:text-white'}`}>
            <ICONS.Users />
            <span className={`text-[9px] font-black uppercase tracking-widest transition-opacity ${isActive('/staff') ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>Staff</span>
          </Link>
        )}
        {canSee([UserRole.ADMIN, UserRole.SUPERADMIN, UserRole.STAFF, UserRole.TOTEM]) && (
          <Link title="Monitor" to="/display" className={`flex flex-col items-center gap-1.5 transition-all group ${isActive('/display') ? 'text-indigo-400 scale-110' : 'text-slate-500 hover:text-white'}`}>
            <ICONS.Screen />
            <span className={`text-[9px] font-black uppercase tracking-widest transition-opacity ${isActive('/display') ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>Live</span>
          </Link>
        )}
        {canSee([UserRole.ADMIN, UserRole.SUPERADMIN]) && (
          <Link title="Admin" to="/admin" className={`flex flex-col items-center gap-1.5 transition-all group ${isActive('/admin') ? 'text-indigo-400 scale-110' : 'text-slate-500 hover:text-white'}`}>
            <ICONS.Activity />
            <span className={`text-[9px] font-black uppercase tracking-widest transition-opacity ${isActive('/admin') ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>BI Hub</span>
          </Link>
        )}
      </div>

      <button 
        onClick={logout}
        className="w-11 h-11 rounded-[1.25rem] bg-rose-500/20 text-rose-500 flex items-center justify-center hover:bg-rose-500 hover:text-white transition-all duration-300 shadow-xl shadow-rose-950/20"
      >
        <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/></svg>
      </button>
    </nav>
  );
};

const AdminPanel: React.FC<{ 
  reset: () => void, 
  userRole: UserRole, 
  users: User[],
  onAddUser: (u: Omit<User, 'id'>) => void,
  onUpdateUser: (id: string, u: Partial<User>) => void,
  onDeleteUser: (id: string) => void,
  services: Service[],
  onAddService: (s: Omit<Service, 'id'>) => void,
  onUpdateService: (id: string, s: Partial<Service>) => void,
  onDeleteService: (id: string) => void,
  stations: Station[],
  onAddStation: (st: Omit<Station, 'id'>) => void,
  onUpdateStation: (id: string, st: Partial<Station>) => void,
  onDeleteStation: (id: string) => void
}> = ({ reset, userRole, users, onAddUser, onUpdateUser, onDeleteUser, services, onAddService, onUpdateService, onDeleteService, stations, onAddStation, onUpdateStation, onDeleteStation }) => {
  const [activeTab, setActiveTab] = useState<'users' | 'services' | 'stations'>('users');

  if (userRole !== UserRole.SUPERADMIN) return null;

  return (
    <div className="max-w-7xl mx-auto px-6 py-12 space-y-12 animate-fade-in pb-32">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
        <div className="lg:col-span-9 space-y-8">
          <div className="bg-white p-2 rounded-[2rem] premium-shadow border border-slate-200/60 inline-flex gap-2">
            {[
              { id: 'users', label: 'Operadores', icon: <ICONS.Users /> },
              { id: 'services', label: 'Servicios', icon: <ICONS.Activity /> },
              { id: 'stations', label: 'Módulos', icon: <ICONS.Terminal /> },
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`flex items-center gap-3 px-8 py-3.5 rounded-2xl text-xs font-black uppercase tracking-widest transition-all duration-300 ${
                  activeTab === tab.id 
                  ? "bg-slate-900 text-white shadow-xl" 
                  : "text-slate-400 hover:text-slate-600 hover:bg-slate-100"
                }`}
              >
                {tab.label}
              </button>
            ))}
          </div>

          <div className="bg-white rounded-[3.5rem] border border-slate-200/60 premium-shadow overflow-hidden">
            {activeTab === 'users' && <UserManagementView users={users} onAdd={onAddUser} onUpdate={onUpdateUser} onDelete={onDeleteUser} stations={stations} />}
            {activeTab === 'services' && <ServiceManagementView services={services} onAdd={onAddService} onUpdate={onUpdateService} onDelete={onDeleteService} />}
            {activeTab === 'stations' && <StationManagementView stations={stations} services={services} onAdd={onAddStation} onUpdate={onUpdateStation} onDelete={onDeleteStation} />}
          </div>
        </div>

        <div className="lg:col-span-3 space-y-8">
          <div className="bg-[#020617] p-10 rounded-[3.5rem] text-white space-y-8 shadow-2xl border border-white/5 relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:scale-125 transition-transform duration-700">
               <svg xmlns="http://www.w3.org/2000/svg" width="120" height="120" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12.22 2h-.44a2 2 0 0 0-2 2v.18a2 2 0 0 1-1 1.73l-.43.25a2 2 0 0 1-2 0l-.15-.08a2 2 0 0 0-2.73.73l-.22.38a2 2 0 0 0 .73 2.73l.15.1a2 2 0 0 1 1 1.72v.51a2 2 0 0 1-1 1.74l-.15.09a2 2 0 0 0-.73 2.73l.22.38a2 2 0 0 0 2.73.73l.15-.08a2 2 0 0 1 2 0l.43.25a2 2 0 0 1 1 1.73V20a2 2 0 0 0 2 2h.44a2 2 0 0 0 2-2v-.18a2 2 0 0 1 1-1.73l.43-.25a2 2 0 0 1 2 0l.15.08a2 2 0 0 0 2.73-.73l.22-.39a2 2 0 0 0-.73-2.73l-.15-.08a2 2 0 0 1-1-1.74v-.5a2 2 0 0 1 1-1.74l.15-.09a2 2 0 0 0 .73-2.73l-.22-.38a2 2 0 0 0-2.73-.73l-.15.08a2 2 0 0 1-2 0l-.43-.25a2 2 0 0 1-1-1.73V4a2 2 0 0 0-2-2z"/><circle cx="12" cy="12" r="3"/></svg>
            </div>
            <h3 className="text-sm font-black uppercase tracking-[0.3em] text-indigo-400">Master Control</h3>
            <p className="text-xs text-slate-500 leading-relaxed font-medium">Configuración centralizada de infraestructura crítica y privilegios de acceso para la red hospitalaria GESFIL.</p>

            <div className="pt-4">
              <button 
                onClick={reset}
                className="w-full py-5 bg-rose-500/10 text-rose-500 rounded-2xl border border-rose-500/20 font-black hover:bg-rose-500 hover:text-white transition-all duration-500 flex items-center justify-center gap-3 uppercase tracking-widest text-[10px]"
              >
                Purgar Instancia
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const { 
    state, addTicket, updateTicketStatus, resetSystem, login, logout, 
    addUser, updateUser, deleteUser,
    addService, updateService, deleteService,
    addStation, updateStation, deleteStation
  } = useQmsStore();

  if (!state.currentUser) {
    return <LoginView onLogin={login} />;
  }

  const role = state.currentUser.role;
  const user = state.currentUser;

  const filteredStations = state.stations.filter(s => {
    if (!s.active) return false;
    if (role === UserRole.STAFF) {
      return s.id === user.assignedStationId;
    }
    return true;
  });

  return (
    <Router>
      <div className="min-h-screen pb-32 bg-[#f8fafc]">
        <Routes>
          <Route path="/" element={
            [UserRole.TOTEM, UserRole.ADMIN, UserRole.SUPERADMIN].includes(role) 
              ? <TotemView services={state.services.filter(s => s.active)} nextSequence={state.nextSequence} onIssueTicket={addTicket} /> 
              : <Navigate to="/staff" />
          } />

          <Route path="/staff" element={
            [UserRole.STAFF, UserRole.ADMIN, UserRole.SUPERADMIN].includes(role) ? (
              <div className="py-12 px-8 h-screen">
                <div className="flex overflow-x-auto gap-8 pb-12 snap-x snap-mandatory scrollbar-hide">
                  {filteredStations.length > 0 ? (
                    filteredStations.map(s => (
                      <StaffView 
                        key={s.id} 
                        station={s} 
                        tickets={state.tickets} 
                        services={state.services} 
                        onStatusUpdate={updateTicketStatus} 
                      />
                    ))
                  ) : (
                    <div className="h-[500px] w-full flex flex-col items-center justify-center text-slate-400 max-w-lg text-center mx-auto space-y-6 animate-fade-in">
                       <div className="w-24 h-24 bg-slate-100 rounded-[2.5rem] flex items-center justify-center text-5xl grayscale opacity-50">🔒</div>
                       <h2 className="text-3xl font-black text-slate-900 tracking-tight">Acceso Restringido</h2>
                       <p className="text-slate-500 font-medium leading-relaxed italic">Su perfil no cuenta con una estación de trabajo activa vinculada. Contacte con la administración de GESFIL para su asignación.</p>
                    </div>
                  )}
                </div>
              </div>
            ) : <Navigate to="/" />
          } />

          <Route path="/display" element={<PublicDisplayView tickets={state.tickets} stations={state.stations} services={state.services} />} />

          <Route path="/admin" element={
            [UserRole.ADMIN, UserRole.SUPERADMIN].includes(role) ? (
              <div className="space-y-4">
                {role === UserRole.ADMIN && (
                   <DashboardView 
                    tickets={state.tickets} 
                    services={state.services} 
                    stations={state.stations} 
                    onToggleService={(id, active) => updateService(id, { active })}
                  />
                )}
                {role === UserRole.SUPERADMIN && (
                   <>
                    <TechnicalInfoView state={state} />
                    <AdminPanel 
                      reset={resetSystem} 
                      userRole={role} 
                      users={state.users}
                      onAddUser={addUser}
                      onUpdateUser={updateUser}
                      onDeleteUser={deleteUser}
                      services={state.services}
                      onAddService={addService}
                      onUpdateService={updateService}
                      onDeleteService={deleteService}
                      stations={state.stations}
                      onAddStation={addStation}
                      onUpdateStation={updateStation}
                      onDeleteStation={deleteStation}
                    />
                   </>
                )}
              </div>
            ) : <Navigate to="/" />
          } />

          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
        <Nav role={role} logout={logout} currentUser={state.currentUser} />
      </div>
    </Router>
  );
};

export default App;
